module top_module(CLK, EN, TE, ENCLK);input CLK, EN, TE;
  output ENCLK;
  reg [6:0] shift_reg;

  assign ENCLK = EN;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin
    if (EN) begin
      shift_reg <= {shift_reg[5:0], TE};
    end
  end

endmodule
